const entretien = $input.first().json;
const entreprise = entretien['Entreprise'];

return {
  title: `Entretien: ${entreprise}`,
  pageId: entretien.id,
  entreprise: entreprise,
  contrat: entretien.Contrat,
  typeEntretien: entretien['Type Entretien'],
  dateEntretien: entretien['Date Entretien'].start
};

const tasks = $input.first().json.tasks;
const targetTitle = $('Format').first().json.title;

const foundTask = tasks.find(task => task.title === targetTitle);

return foundTask ? {id: foundTask.id} : {id: null};

// Déclaration des constantes
const mapping = $('Mapping').first().json;
const TRAVAIL_PROJECT_ID = '66ba4bbedb643ca0adb34ab0';

// Récupération du tableau d'items produit par l'agent
const checklist = $input.first().json.output;

// Groupement par section
const sections = checklist.reduce((acc, { section, title }) => {
  (acc[section] ||= []).push(title);
  return acc;
}, {});

// Construction du contenu formaté
const content =
  `📋 Préparation Entretien ${mapping.entreprise}\n\n` +
  Object.entries(sections)
    .map(([section, titles]) => {
      const lines = titles.map(t => `  • ${t}`).join('\n');
      return `${section}\n${lines}\n`;
    })
    .join('\n');

// Création des sous-tâches TickTick
const items = checklist.map(({ section, title }) => ({
  title: `${section} - ${title}`,
  status: 0
}));

// Retour final vers TickTick API
return {
  projectId: TRAVAIL_PROJECT_ID,
  title: mapping.title,
  content: content.trim(),
  startDate: mapping.dateEntretien,
  tags: ["🤖Auto", "🕒1h"],
  items
};

